_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv1 = (vUv-.5) * uAspect.xy;


vec2 uv6 = uv1;
float z = (q28-1)*length(uv1)+rand_frame * 86;
vec2 d = normalize(uv1);
vec2 rs = clamp(tan(z)*d,-18,18);
vUv += 1*GetBlur1(vUv)*vec2 (0,1)+0.01*rs;


uv6 = .4*sin(uv1*2*q28+rand_frame);

mus = .06/(length(uv6));
mus *= roam_sin;
mus = mix(mus, lum(mus), clamp01(.2*lum(mus)));

vec3 blur = GetBlur2(fract(vUv));

vec3 crisp= GetPixel((vUv-.5)*1.01+.48);

vec3 ret1 = crisp - blur*.03 + .15*mus;

q25 = q24;
ret = q25*(ret1*.97-.02) + (1-q25)* GetPixel(vUvOriginal);


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
dz = 0;

vec2 hor = vec2(uTexSize.z,0);
vec2 ver = vec2(0,uTexSize.w);

float dist = 1;
float inten = 1;
ret1 = 0;
float anz = 3;
float n = 0;


uv4 = vUv+0*vec2(q10,q11);
    dz.x = lum(GetPixel(uv4+hor)- GetPixel (uv4-hor));
    dz.y = lum(GetPixel(uv4+ver)- GetPixel (uv4-ver));


mus = GetPixel(.1*dz)+.01;

uv2 = vUv-.5;
dz = 0;
while (n <= anz) {
    dist = 1-fract(1.0/anz*n-.01); //evtl sqrt !;

    uv3 = 2*uv2*dist + .5 + vec2(q30,q30/2);
    uv3 = fract(uv3);
    uv3 *= uAspect.xy;
    uv3 = .4 * cos(16*uv3);
    neu = .03/length(uv3);
    neu = dist*neu + (1-dist)*lum(neu);
    ret1 = max(ret1,neu);
n++;
}

ret = GetPixel(vUvOriginal*.8) +  mus*6 + 32*(ret1*mus);

  fragColor = ret;
}
